import Model from 'flarum/common/Model';
export default class PickEvent extends Model {
  weekId = (() => Model.attribute('weekId'))();
  homeTeamId = (() => Model.attribute('homeTeamId'))();
  awayTeamId = (() => Model.attribute('awayTeamId'))();
  cfbdId = (() => Model.attribute('cfbdId'))();
  neutralSite = (() => Model.attribute('neutralSite'))();
  matchDate = (() => Model.attribute('matchDate'))();
  cutoffDate = (() => Model.attribute('cutoffDate'))();
  status = (() => Model.attribute('status'))();
  homeScore = (() => Model.attribute('homeScore'))();
  awayScore = (() => Model.attribute('awayScore'))();
  result = (() => Model.attribute('result'))();
  canPick = (() => Model.attribute('canPick'))();
  week = (() => Model.hasOne('week'))();
  homeTeam = (() => Model.hasOne('homeTeam'))();
  awayTeam = (() => Model.hasOne('awayTeam'))();
}
flarum.reg.add('resofire-picks', 'common/models/PickEvent', PickEvent);